// Slack sends slash command data as application/x-www-form-urlencoded
const raw = $input.first().json.body || '';
const params = {};

if (typeof raw === 'string') {
  raw.split('&').forEach(pair => {
    const [key, val] = pair.split('=');
    if (key) params[decodeURIComponent(key)] = decodeURIComponent((val || '').replace(/\+/g, ' '));
  });
} else if (typeof raw === 'object') {
  // n8n may pre-parse it
  Object.assign(params, raw);
}

const text = params.text || params.body?.text || '';
const userId = params.user_id || '';
const userName = params.user_name || 'Devon';
const responseUrl = params.response_url || '';
const channelId = params.channel_id || '';

if (!text || text.trim() === '') {
  return [{
    json: {
      error: true,
      message: 'No seed idea provided',
      response_url: responseUrl,
      user_id: userId
    }
  }];
}

return [{
  json: {
    raw_text: text.trim(),
    user_id: userId,
    user_name: userName,
    response_url: responseUrl,
    channel_id: channelId,
    timestamp: new Date().toISOString()
  }
}];

