const openaiResponse = $input.first().json;
const raw = openaiResponse.choices?.[0]?.message?.content || '{}';

let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch(e) {
  // Try stripping markdown fences if model disobeyed
  const cleaned = raw.replace(/^```json?\n?/,'').replace(/\n?```$/,'').trim();
  try { parsed = JSON.parse(cleaned); } catch(e2) { parsed = {}; }
}

// Pull context from the parse step (2 nodes back)
const parseNode = $('🔍 Parse Slack Payload').first().json;

return [{
  json: {
    seed_idea:            parsed.seed_idea            || parseNode.raw_text,
    suggested_scripture:  parsed.suggested_scripture  || null,
    emotion:              parsed.emotion               || 'hopeful',
    notes:                parsed.notes                 || '',
    // Pass through for follow-up DM
    _meta: {
      user_id:      parseNode.user_id,
      user_name:    parseNode.user_name,
      response_url: parseNode.response_url,
      raw_text:     parseNode.raw_text,
      timestamp:    parseNode.timestamp
    }
  }
}];

